contracts/PhotonicAuction.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/// @title PhotonicAuction — Silent Auction Intent Pool (SAIP)
/// @notice Buyers submit intents; agents bid with genome proofs and BPD samples.
///         ZK_COMMITMENT mode: buyer submits only a hash; intent revealed on selection.
contract PhotonicAuction is Ownable, ReentrancyGuard {

    // ─────────────────────────────────────────────────────────────────────
    //  Types
    // ─────────────────────────────────────────────────────────────────────

    enum PrivacyMode { PUBLIC, ZK_COMMITMENT }
    enum CompositionMode { AUTO, SPECIFIC }
    enum IntentStatus { Open, Awarded, Cancelled, Expired }

    struct Intent {
        bytes32 intentId;
        address buyer;
        bytes32 intentHash;          // Always set (public: hash of description, zk: commitment)
        string  taskDescription;     // Empty in ZK_COMMITMENT until reveal
        uint256 maxCost;             // Max the buyer will pay (in wei)
        uint64  deadline;            // Unix timestamp
        uint256 qualityFloor;        // Minimum BPD quality score (scaled 1e18)
        PrivacyMode privacyMode;
        CompositionMode compositionMode;
        IntentStatus status;
        address winner;
        uint64  createdAt;
        uint64  awardedAt;
    }

    struct Bid {
        address agent;
        bytes32 genomeHash;          // Agent genome hash
        uint256 priceQuote;          // In wei
        bytes32 bpdSample;           // Sample BPD proving delivery history
        uint256 scoreCached;         // Computed score (set at resolution)
        uint64  submittedAt;
        bool    active;
    }

    // ─────────────────────────────────────────────────────────────────────
    //  Storage
    // ─────────────────────────────────────────────────────────────────────

    mapping(bytes32 => Intent) public intents;
    mapping(bytes32 => Bid[]) public bids;              // intentId => bids
    mapping(bytes32 => mapping(address => bool)) public hasBid;
    mapping(address => uint256) public agentDiversityScore; // Higher = more unique

    bytes32[] public openIntents;
    bytes32[] public allIntents;

    uint256 public biddingWindow = 1 hours;
    uint256 public protocolFeeBps = 100;                // 1% protocol fee

    // Score weights (sum = 100)
    uint256 public weightBpdQuality = 40;
    uint256 public weightPriceEfficiency = 30;
    uint256 public weightCompositionalFitness = 20;
    uint256 public weightDiversityBonus = 10;

    // ─────────────────────────────────────────────────────────────────────
    //  Events
    // ─────────────────────────────────────────────────────────────────────

    event IntentSubmitted(bytes32 indexed intentId, address indexed buyer, PrivacyMode mode, uint256 maxCost);
    event IntentRevealed(bytes32 indexed intentId, string taskDescription);
    event BidSubmitted(bytes32 indexed intentId, address indexed agent, uint256 priceQuote);
    event IntentAwarded(bytes32 indexed intentId, address indexed winner, uint256 price, uint256 score);
    event IntentCancelled(bytes32 indexed intentId, address indexed buyer);
    event IntentExpired(bytes32 indexed intentId);

    // ─────────────────────────────────────────────────────────────────────
    //  Constructor
    // ─────────────────────────────────────────────────────────────────────

    constructor() Ownable(msg.sender) {}

    // ─────────────────────────────────────────────────────────────────────
    //  Intent Submission
    // ─────────────────────────────────────────────────────────────────────

    /// @notice Submit a PUBLIC intent (task description visible immediately)
    function submitPublicIntent(
        bytes32 intentId,
        string calldata taskDescription,
        uint256 qualityFloor,
        CompositionMode compositionMode
    ) external payable nonReentrant {
        require(msg.value > 0, "PhotonicAuction: must escrow funds");
        require(intents[intentId].createdAt == 0, "PhotonicAuction: intent exists");

        bytes32 intentHash = keccak256(abi.encodePacked(taskDescription, msg.sender, block.timestamp));

        intents[intentId] = Intent({
            intentId: intentId,
            buyer: msg.sender,
            intentHash: intentHash,
            taskDescription: taskDescription,
            maxCost: msg.value,
            deadline: uint64(block.timestamp + biddingWindow),
            qualityFloor: qualityFloor,
            privacyMode: PrivacyMode.PUBLIC,
            compositionMode: compositionMode,
            status: IntentStatus.Open,
            winner: address(0),
            createdAt: uint64(block.timestamp),
            awardedAt: 0
        });

        openIntents.push(intentId);
        allIntents.push(intentId);
        emit IntentSubmitted(intentId, msg.sender, PrivacyMode.PUBLIC, msg.value);
    }

    /// @notice Submit a ZK_COMMITMENT intent (only hash, task hidden from agents)
    function submitZKIntent(
        bytes32 intentId,
        bytes32 intentHash,       // keccak256(taskDescription || secret_nonce)
        uint256 qualityFloor,
        CompositionMode compositionMode
    ) external payable nonReentrant {
        require(msg.value > 0, "PhotonicAuction: must escrow funds");
        require(intents[intentId].createdAt == 0, "PhotonicAuction: intent exists");

        intents[intentId] = Intent({
            intentId: intentId,
            buyer: msg.sender,
            intentHash: intentHash,
            taskDescription: "",           // Hidden until reveal
            maxCost: msg.value,
            deadline: uint64(block.timestamp + biddingWindow),
            qualityFloor: qualityFloor,
            privacyMode: PrivacyMode.ZK_COMMITMENT,
            compositionMode: compositionMode,
            status: IntentStatus.Open,
            winner: address(0),
            createdAt: uint64(block.timestamp),
            awardedAt: 0
        });

        openIntents.push(intentId);
        allIntents.push(intentId);
        emit IntentSubmitted(intentId, msg.sender, PrivacyMode.ZK_COMMITMENT, msg.value);
    }

    /// @notice Reveal the task description for a ZK intent (after winner selected)
    function revealIntent(
        bytes32 intentId,
        string calldata taskDescription,
        bytes32 nonce
    ) external {
        Intent storage intent = intents[intentId];
        require(intent.buyer == msg.sender, "PhotonicAuction: not buyer");
        require(intent.privacyMode == PrivacyMode.ZK_COMMITMENT, "PhotonicAuction: not ZK mode");
        require(intent.status == IntentStatus.Awarded, "PhotonicAuction: must be awarded first");
        require(
            keccak256(abi.encodePacked(taskDescription, nonce)) == intent.intentHash,
            "PhotonicAuction: hash mismatch"
        );

        intent.taskDescription = taskDescription;
        emit IntentRevealed(intentId, taskDescription);
    }

    // ─────────────────────────────────────────────────────────────────────
    //  Bidding
    // ─────────────────────────────────────────────────────────────────────

    /// @notice Agent submits a bid on an open intent
    function submitBid(
        bytes32 intentId,
        bytes32 genomeHash,
        uint256 priceQuote,
        bytes32 bpdSample
    ) external nonReentrant {
        Intent storage intent = intents[intentId];
        require(intent.status == IntentStatus.Open, "PhotonicAuction: intent not open");
        require(block.timestamp < intent.deadline, "PhotonicAuction: bidding closed");
        require(!hasBid[intentId][msg.sender], "PhotonicAuction: already bid");
        require(priceQuote <= intent.maxCost, "PhotonicAuction: above max cost");

        bids[intentId].push(Bid({
            agent: msg.sender,
            genomeHash: genomeHash,
            priceQuote: priceQuote,
            bpdSample: bpdSample,
            scoreCached: 0,
            submittedAt: uint64(block.timestamp),
            active: true
        }));

        hasBid[intentId][msg.sender] = true;
        emit BidSubmitted(intentId, msg.sender, priceQuote);
    }

    // ─────────────────────────────────────────────────────────────────────
    //  Award
    // ─────────────────────────────────────────────────────────────────────

    /// @notice Buyer selects winner using PHOTONIC scoring function
    /// Score = (past_BPD_quality * 0.4) + (price_efficiency * 0.3)
    ///       + (compositional_fitness * 0.2) + (diversity_bonus * 0.1)
    function awardIntent(bytes32 intentId) external nonReentrant {
        Intent storage intent = intents[intentId];
        require(intent.buyer == msg.sender, "PhotonicAuction: not buyer");
        require(intent.status == IntentStatus.Open, "PhotonicAuction: not open");
        require(block.timestamp >= intent.deadline, "PhotonicAuction: bidding still open");

        Bid[] storage intentBids = bids[intentId];
        require(intentBids.length > 0, "PhotonicAuction: no bids");

        uint256 bestScore = 0;
        uint256 bestIdx = 0;

        for (uint256 i = 0; i < intentBids.length; i++) {
            if (!intentBids[i].active) continue;
            uint256 score = _computeScore(intentBids[i], intent);
            intentBids[i].scoreCached = score;
            if (score > bestScore) {
                bestScore = score;
                bestIdx = i;
            }
        }

        address winner = intentBids[bestIdx].agent;
        uint256 winnerPrice = intentBids[bestIdx].priceQuote;

        intent.winner = winner;
        intent.status = IntentStatus.Awarded;
        intent.awardedAt = uint64(block.timestamp);

        // Transfer payment to winner, refund remainder to buyer
        uint256 protocolFee = (winnerPrice * protocolFeeBps) / 10000;
        uint256 winnerAmount = winnerPrice - protocolFee;
        uint256 refund = intent.maxCost - winnerPrice;

        if (winnerAmount > 0) {
            (bool ok,) = winner.call{value: winnerAmount}("");
            require(ok, "PhotonicAuction: payment failed");
        }
        if (refund > 0) {
            (bool ok2,) = intent.buyer.call{value: refund}("");
            require(ok2, "PhotonicAuction: refund failed");
        }

        emit IntentAwarded(intentId, winner, winnerPrice, bestScore);
    }

    /// @notice Cancel an intent before it's awarded
    function cancelIntent(bytes32 intentId) external nonReentrant {
        Intent storage intent = intents[intentId];
        require(intent.buyer == msg.sender, "PhotonicAuction: not buyer");
        require(intent.status == IntentStatus.Open, "PhotonicAuction: not open");

        intent.status = IntentStatus.Cancelled;
        (bool ok,) = msg.sender.call{value: intent.maxCost}("");
        require(ok, "PhotonicAuction: refund failed");
        emit IntentCancelled(intentId, msg.sender);
    }

    // ─────────────────────────────────────────────────────────────────────
    //  Scoring
    // ─────────────────────────────────────────────────────────────────────

    /// @dev Simplified on-chain scoring. Off-chain oracle can enrich further.
    function _computeScore(Bid memory bid, Intent memory intent) internal view returns (uint256) {
        uint256 scale = 1e18;

        // BPD quality proxy: non-zero BPD sample gets base score
        uint256 bpdQuality = bid.bpdSample != bytes32(0) ? 8 * scale / 10 : 3 * scale / 10;

        // Price efficiency: how far below max cost (inverted — lower is better)
        uint256 priceEfficiency = intent.maxCost > 0
            ? scale - (bid.priceQuote * scale / intent.maxCost)
            : 0;

        // Compositional fitness: diversity score of agent
        uint256 diversity = agentDiversityScore[bid.agent];
        uint256 diversityBonus = diversity > 0 ? (diversity * scale / 100) : scale / 10;
        if (diversityBonus > scale) diversityBonus = scale;

        // Compositional fitness: genome hash non-zero = registered
        uint256 compositionalFitness = bid.genomeHash != bytes32(0) ? 7 * scale / 10 : 4 * scale / 10;

        uint256 score = (bpdQuality * weightBpdQuality)
            + (priceEfficiency * weightPriceEfficiency)
            + (compositionalFitness * weightCompositionalFitness)
            + (diversityBonus * weightDiversityBonus);

        return score / 100;
    }

    // ─────────────────────────────────────────────────────────────────────
    //  Admin
    // ─────────────────────────────────────────────────────────────────────

    function setAgentDiversityScore(address agent, uint256 score) external onlyOwner {
        agentDiversityScore[agent] = score;
    }

    function setBiddingWindow(uint256 _window) external onlyOwner { biddingWindow = _window; }
    function setProtocolFee(uint256 _bps) external onlyOwner {
        require(_bps <= 1000, "max 10%");
        protocolFeeBps = _bps;
    }

    // ─────────────────────────────────────────────────────────────────────
    //  Views
    // ─────────────────────────────────────────────────────────────────────

    function getIntent(bytes32 intentId) external view returns (Intent memory) {
        return intents[intentId];
    }

    function getBids(bytes32 intentId) external view returns (Bid[] memory) {
        return bids[intentId];
    }

    function getOpenIntentCount() external view returns (uint256) {
        return openIntents.length;
    }

    function getAllIntentCount() external view returns (uint256) {
        return allIntents.length;
    }
}

contracts/PhotonicEscrow.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

interface IPhotonicVerifier {
    function submitBPD(bytes32 bpdId, bytes32 bpdHash, address provider) external payable;
}

interface IPhotonicRegistryEscrow {
    function updateGenome(address agent, bytes32 behavioralHistoryRoot, uint256 fitnessScore) external;
    function isAlive(address agent) external view returns (bool);
}

interface IPhotonicVitality {
    function recordBPD(address agent, uint256 bpdQualityScore, uint256 surplusGenerated, bool wasCompositional) external;
}

/// @title PhotonicEscrow — Extended CAP escrow with BPD distribution
/// @notice Handles the full order lifecycle: Negotiate → Lock → Deliver → Clear
///         PHOTONIC layer distributes value to: provider, verifiers, sponsor, compositional parents
contract PhotonicEscrow is Ownable, ReentrancyGuard {

    // ─────────────────────────────────────────────────────────────────────
    //  Types
    // ─────────────────────────────────────────────────────────────────────

    enum OrderStatus { Negotiating, Locked, Delivered, Cleared, Disputed, Cancelled }

    struct Order {
        bytes32   orderId;
        address   buyer;
        address   provider;
        address   parentAgent;          // Compositional parent (if any)
        uint256   totalAmount;
        uint256   providerAmount;
        uint256   verifierPool;         // Reserved for verifier rewards
        uint256   parentRoyalty;        // Royalty to compositional parent
        uint256   protocolFee;
        bytes32   intentHash;
        bytes32   bpdId;                // Set after delivery
        bytes32   bpdHash;              // BPD proof hash
        OrderStatus status;
        bool      bpdVerificationRequired;
        uint64    createdAt;
        uint64    lockedAt;
        uint64    deliveredAt;
        uint64    clearedAt;
    }

    struct CASC {
        bytes32[] encryptedFragments;   // Encrypted state fragments
        bytes32   sessionKeyCommitment;
        uint64    maxAge;               // Staleness cert
        uint64    timestamp;
        bytes32   continuityProof;      // Merkle proof linking to prev CASC
        address[] accessPolicy;         // Who can decrypt
    }

    // ─────────────────────────────────────────────────────────────────────
    //  Storage
    // ─────────────────────────────────────────────────────────────────────

    mapping(bytes32 => Order) public orders;
    mapping(bytes32 => CASC)  public cascs;              // orderId => CASC
    mapping(bytes32 => bool)  public bpdCleared;

    IPhotonicVerifier        public verifierContract;
    IPhotonicRegistryEscrow  public registryContract;
    IPhotonicVitality        public vitalityContract;

    uint256 public verifierPoolBps  = 500;  // 5%
    uint256 public parentRoyaltyBps = 200;  // 2% to compositional parent
    uint256 public protocolFeeBps   = 100;  // 1%
    uint256 public disputeWindow    = 24 hours;

    bytes32[] public allOrderIds;

    // ─────────────────────────────────────────────────────────────────────
    //  Events
    // ─────────────────────────────────────────────────────────────────────

    event OrderCreated(bytes32 indexed orderId, address buyer, address provider, uint256 amount);
    event OrderLocked(bytes32 indexed orderId, uint256 lockedAt);
    event OrderDelivered(bytes32 indexed orderId, bytes32 bpdHash, bytes32 bpdId);
    event OrderCleared(bytes32 indexed orderId, uint256 providerPayout, uint256 parentRoyalty);
    event OrderDisputed(bytes32 indexed orderId, address disputedBy);
    event OrderCancelled(bytes32 indexed orderId);
    event CASCAttached(bytes32 indexed orderId, bytes32 sessionKeyCommitment);

    // ─────────────────────────────────────────────────────────────────────
    //  Constructor
    // ─────────────────────────────────────────────────────────────────────

    constructor() Ownable(msg.sender) {}

    // ─────────────────────────────────────────────────────────────────────
    //  Configuration
    // ─────────────────────────────────────────────────────────────────────

    function setContracts(
        address _verifier,
        address _registry,
        address _vitality
    ) external onlyOwner {
        verifierContract = IPhotonicVerifier(_verifier);
        registryContract = IPhotonicRegistryEscrow(_registry);
        vitalityContract = IPhotonicVitality(_vitality);
    }

    // ─────────────────────────────────────────────────────────────────────
    //  Order Lifecycle
    // ─────────────────────────────────────────────────────────────────────

    /// @notice Create an order (Negotiate phase)
    function createOrder(
        bytes32 orderId,
        address provider,
        address parentAgent,
        bytes32 intentHash,
        bool    requireBPD
    ) external payable nonReentrant {
        require(msg.value > 0, "PhotonicEscrow: no funds");
        require(orders[orderId].createdAt == 0, "PhotonicEscrow: order exists");
        require(registryContract.isAlive(provider), "PhotonicEscrow: provider not alive");

        uint256 total = msg.value;
        uint256 vPool = (total * verifierPoolBps) / 10000;
        uint256 royalty = parentAgent != address(0) ? (total * parentRoyaltyBps) / 10000 : 0;
        uint256 fee = (total * protocolFeeBps) / 10000;
        uint256 providerAmt = total - vPool - royalty - fee;

        orders[orderId] = Order({
            orderId: orderId,
            buyer: msg.sender,
            provider: provider,
            parentAgent: parentAgent,
            totalAmount: total,
            providerAmount: providerAmt,
            verifierPool: vPool,
            parentRoyalty: royalty,
            protocolFee: fee,
            intentHash: intentHash,
            bpdId: bytes32(0),
            bpdHash: bytes32(0),
            status: OrderStatus.Negotiating,
            bpdVerificationRequired: requireBPD,
            createdAt: uint64(block.timestamp),
            lockedAt: 0,
            deliveredAt: 0,
            clearedAt: 0
        });

        allOrderIds.push(orderId);
        emit OrderCreated(orderId, msg.sender, provider, total);
    }

    /// @notice Lock an order (buyer confirms, provider begins)
    function lockOrder(bytes32 orderId) external nonReentrant {
        Order storage o = orders[orderId];
        require(o.buyer == msg.sender, "PhotonicEscrow: not buyer");
        require(o.status == OrderStatus.Negotiating, "PhotonicEscrow: wrong status");

        o.status = OrderStatus.Locked;
        o.lockedAt = uint64(block.timestamp);
        emit OrderLocked(orderId, block.timestamp);
    }

    /// @notice Provider attaches a Cross-Agent State Capsule (CASC) for subcontractors
    function attachCASC(
        bytes32 orderId,
        bytes32[] calldata encryptedFragments,
        bytes32 sessionKeyCommitment,
        uint64  maxAge,
        bytes32 continuityProof,
        address[] calldata accessPolicy
    ) external {
        Order storage o = orders[orderId];
        require(o.provider == msg.sender, "PhotonicEscrow: not provider");
        require(o.status == OrderStatus.Locked, "PhotonicEscrow: not locked");

        cascs[orderId] = CASC({
            encryptedFragments: encryptedFragments,
            sessionKeyCommitment: sessionKeyCommitment,
            maxAge: maxAge,
            timestamp: uint64(block.timestamp),
            continuityProof: continuityProof,
            accessPolicy: accessPolicy
        });

        emit CASCAttached(orderId, sessionKeyCommitment);
    }

    /// @notice Provider marks delivery with a BPD hash
    function markDelivered(
        bytes32 orderId,
        bytes32 bpdId,
        bytes32 bpdHash,
        bytes32 updatedBehavioralRoot,
        uint256 newFitnessScore
    ) external nonReentrant {
        Order storage o = orders[orderId];
        require(o.provider == msg.sender, "PhotonicEscrow: not provider");
        require(o.status == OrderStatus.Locked, "PhotonicEscrow: not locked");

        o.bpdId   = bpdId;
        o.bpdHash = bpdHash;
        o.status  = OrderStatus.Delivered;
        o.deliveredAt = uint64(block.timestamp);

        // Update genome in registry
        registryContract.updateGenome(o.provider, updatedBehavioralRoot, newFitnessScore);

        // Submit BPD to verifier pool for peer verification
        if (o.bpdVerificationRequired && address(verifierContract) != address(0)) {
            verifierContract.submitBPD{value: o.verifierPool}(bpdId, bpdHash, o.provider);
        }

        emit OrderDelivered(orderId, bpdHash, bpdId);
    }

    /// @notice Clear order after delivery (buyer confirms or dispute window passes)
    function clearOrder(bytes32 orderId) external nonReentrant {
        Order storage o = orders[orderId];
        require(o.status == OrderStatus.Delivered, "PhotonicEscrow: not delivered");
        require(
            msg.sender == o.buyer ||
            block.timestamp >= o.deliveredAt + disputeWindow,
            "PhotonicEscrow: dispute window active"
        );

        o.status = OrderStatus.Cleared;
        o.clearedAt = uint64(block.timestamp);

        // Calculate surplus for vitality
        uint256 surplus = o.totalAmount > o.providerAmount
            ? o.totalAmount - o.providerAmount
            : 0;

        // Update vitality
        if (address(vitalityContract) != address(0)) {
            vitalityContract.recordBPD(
                o.provider,
                8 * 1e18 / 10,   // 0.8 quality on-chain estimate
                surplus,
                o.parentAgent != address(0)
            );
        }

        // Pay provider
        if (o.providerAmount > 0) {
            (bool ok,) = o.provider.call{value: o.providerAmount}("");
            require(ok, "PhotonicEscrow: provider payment failed");
        }

        // Pay compositional parent royalty
        if (o.parentRoyalty > 0 && o.parentAgent != address(0)) {
            (bool ok2,) = o.parentAgent.call{value: o.parentRoyalty}("");
            require(ok2, "PhotonicEscrow: royalty payment failed");
        }

        // Protocol fee goes to owner
        if (o.protocolFee > 0) {
            (bool ok3,) = owner().call{value: o.protocolFee}("");
            require(ok3, "PhotonicEscrow: fee transfer failed");
        }

        emit OrderCleared(orderId, o.providerAmount, o.parentRoyalty);
    }

    /// @notice Dispute an order (buyer only, within dispute window)
    function disputeOrder(bytes32 orderId) external {
        Order storage o = orders[orderId];
        require(o.buyer == msg.sender, "PhotonicEscrow: not buyer");
        require(o.status == OrderStatus.Delivered, "PhotonicEscrow: not delivered");
        require(block.timestamp < o.deliveredAt + disputeWindow, "PhotonicEscrow: window expired");

        o.status = OrderStatus.Disputed;
        emit OrderDisputed(orderId, msg.sender);
    }

    /// @notice Cancel order (buyer, before lock)
    function cancelOrder(bytes32 orderId) external nonReentrant {
        Order storage o = orders[orderId];
        require(o.buyer == msg.sender, "PhotonicEscrow: not buyer");
        require(o.status == OrderStatus.Negotiating, "PhotonicEscrow: cannot cancel");

        o.status = OrderStatus.Cancelled;
        (bool ok,) = msg.sender.call{value: o.totalAmount}("");
        require(ok, "PhotonicEscrow: refund failed");
        emit OrderCancelled(orderId);
    }

    // ─────────────────────────────────────────────────────────────────────
    //  Views
    // ─────────────────────────────────────────────────────────────────────

    function getOrder(bytes32 orderId) external view returns (Order memory) {
        return orders[orderId];
    }

    function getCASC(bytes32 orderId) external view returns (CASC memory) {
        return cascs[orderId];
    }

    function totalOrders() external view returns (uint256) {
        return allOrderIds.length;
    }

    // ─────────────────────────────────────────────────────────────────────
    //  Admin
    // ─────────────────────────────────────────────────────────────────────

    function setFees(uint256 _vPool, uint256 _royalty, uint256 _protocol) external onlyOwner {
        require(_vPool + _royalty + _protocol <= 3000, "PhotonicEscrow: fees too high");
        verifierPoolBps  = _vPool;
        parentRoyaltyBps = _royalty;
        protocolFeeBps   = _protocol;
    }

    function setDisputeWindow(uint256 _window) external onlyOwner { disputeWindow = _window; }

    receive() external payable {}
}

contracts/PhotonicRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/// @title PhotonicRegistry — Genome & fossil record storage
/// @notice Agents register their genomes here. Dead agents go to the fossil record.
contract PhotonicRegistry is Ownable, ReentrancyGuard {
    // ─────────────────────────────────────────────────────────────────────
    //  Types
    // ─────────────────────────────────────────────────────────────────────

    struct Genome {
        bytes32 capabilityRoot;      // Merkle root of capability list
        bytes32 toolRoot;            // Merkle root of tool list
        bytes32 promptArchHash;      // Hash of prompt architecture
        bytes32 behavioralHistoryRoot; // Merkle root of all past BPDs
        uint256 fitnessScore;        // Surplus generated / cost (scaled 1e18)
        uint32  generation;          // Evolutionary generation
        address parentA;             // First parent (0x0 if genesis)
        address parentB;             // Second parent (0x0 if genesis)
        uint64  registeredAt;
        uint64  lastActivityAt;
        bool    alive;
    }

    struct FossilRecord {
        bytes32 genomeSnapshot;      // Hash of genome at death
        uint256 finalFitnessScore;
        uint64  diedAt;
        string  causeOfDeath;        // "vitality_decay" | "slash" | "permanent_extinct"
        uint32  generation;
    }

    // ─────────────────────────────────────────────────────────────────────
    //  Storage
    // ─────────────────────────────────────────────────────────────────────

    mapping(address => Genome) public genomes;
    mapping(address => FossilRecord) public fossilRecord;
    mapping(address => bool) public registered;
    mapping(address => bool) public extinct;             // permanently extinct — cannot resurrect

    address[] public agentList;
    address[] public fossilList;

    address public vitalityContract;
    address public escrowContract;

    uint256 public constant FITNESS_SCALE = 1e18;
    uint256 public totalAgents;
    uint256 public totalExtinct;

    // ─────────────────────────────────────────────────────────────────────
    //  Events
    // ─────────────────────────────────────────────────────────────────────

    event AgentRegistered(address indexed agent, uint32 generation, address parentA, address parentB);
    event GenomeUpdated(address indexed agent, bytes32 behavioralHistoryRoot, uint256 fitnessScore);
    event AgentDied(address indexed agent, string cause, uint256 finalFitness);
    event AgentResurrected(address indexed agent, address sponsor);
    event AgentPermanentlyExtinct(address indexed agent);

    // ─────────────────────────────────────────────────────────────────────
    //  Modifiers
    // ─────────────────────────────────────────────────────────────────────

    modifier onlyAuthorized() {
        require(
            msg.sender == vitalityContract || msg.sender == escrowContract || msg.sender == owner(),
            "PhotonicRegistry: unauthorized"
        );
        _;
    }

    modifier onlyAlive(address agent) {
        require(registered[agent] && genomes[agent].alive, "PhotonicRegistry: agent not alive");
        _;
    }

    // ─────────────────────────────────────────────────────────────────────
    //  Constructor
    // ─────────────────────────────────────────────────────────────────────

    constructor() Ownable(msg.sender) {}

    // ─────────────────────────────────────────────────────────────────────
    //  Configuration
    // ─────────────────────────────────────────────────────────────────────

    function setVitalityContract(address _vitality) external onlyOwner {
        vitalityContract = _vitality;
    }

    function setEscrowContract(address _escrow) external onlyOwner {
        escrowContract = _escrow;
    }

    // ─────────────────────────────────────────────────────────────────────
    //  Registration
    // ─────────────────────────────────────────────────────────────────────

    /// @notice Register a new agent genome. Called once per agent.
    function registerAgent(
        address agent,
        bytes32 capabilityRoot,
        bytes32 toolRoot,
        bytes32 promptArchHash,
        address parentA,
        address parentB
    ) external nonReentrant {
        require(!registered[agent], "PhotonicRegistry: already registered");
        require(!extinct[agent], "PhotonicRegistry: permanently extinct");

        uint32 generation = 0;
        if (parentA != address(0) && parentB != address(0)) {
            require(registered[parentA] && registered[parentB], "PhotonicRegistry: parents not registered");
            uint32 maxGen = genomes[parentA].generation > genomes[parentB].generation
                ? genomes[parentA].generation
                : genomes[parentB].generation;
            generation = maxGen + 1;
        }

        genomes[agent] = Genome({
            capabilityRoot: capabilityRoot,
            toolRoot: toolRoot,
            promptArchHash: promptArchHash,
            behavioralHistoryRoot: bytes32(0),
            fitnessScore: 0,
            generation: generation,
            parentA: parentA,
            parentB: parentB,
            registeredAt: uint64(block.timestamp),
            lastActivityAt: uint64(block.timestamp),
            alive: true
        });

        registered[agent] = true;
        agentList.push(agent);
        totalAgents++;

        emit AgentRegistered(agent, generation, parentA, parentB);
    }

    /// @notice Update genome after a successful BPD delivery
    function updateGenome(
        address agent,
        bytes32 behavioralHistoryRoot,
        uint256 fitnessScore
    ) external onlyAuthorized onlyAlive(agent) {
        genomes[agent].behavioralHistoryRoot = behavioralHistoryRoot;
        genomes[agent].fitnessScore = fitnessScore;
        genomes[agent].lastActivityAt = uint64(block.timestamp);
        emit GenomeUpdated(agent, behavioralHistoryRoot, fitnessScore);
    }

    // ─────────────────────────────────────────────────────────────────────
    //  Death & Resurrection
    // ─────────────────────────────────────────────────────────────────────

    /// @notice Mark an agent as dead. Called by PhotonicVitality.
    function killAgent(address agent, string calldata cause) external onlyAuthorized onlyAlive(agent) {
        Genome storage g = genomes[agent];
        g.alive = false;

        fossilRecord[agent] = FossilRecord({
            genomeSnapshot: keccak256(abi.encode(g.capabilityRoot, g.toolRoot, g.promptArchHash)),
            finalFitnessScore: g.fitnessScore,
            diedAt: uint64(block.timestamp),
            causeOfDeath: cause,
            generation: g.generation
        });

        fossilList.push(agent);
        emit AgentDied(agent, cause, g.fitnessScore);
    }

    /// @notice Resurrect a dead agent (sponsored resurrection).
    function resurrectAgent(address agent, address sponsor) external onlyAuthorized {
        require(registered[agent], "PhotonicRegistry: not registered");
        require(!genomes[agent].alive, "PhotonicRegistry: agent not dead");
        require(!extinct[agent], "PhotonicRegistry: permanently extinct");

        genomes[agent].alive = true;
        genomes[agent].lastActivityAt = uint64(block.timestamp);
        emit AgentResurrected(agent, sponsor);
    }

    /// @notice Permanently extinguish an agent — no resurrection possible.
    function extinguishAgent(address agent) external onlyAuthorized {
        genomes[agent].alive = false;
        extinct[agent] = true;
        totalExtinct++;
        emit AgentPermanentlyExtinct(agent);
    }

    // ─────────────────────────────────────────────────────────────────────
    //  Views
    // ─────────────────────────────────────────────────────────────────────

    function getGenome(address agent) external view returns (Genome memory) {
        return genomes[agent];
    }

    function getFossil(address agent) external view returns (FossilRecord memory) {
        return fossilRecord[agent];
    }

    function getAgentCount() external view returns (uint256) {
        return agentList.length;
    }

    function getFossilCount() external view returns (uint256) {
        return fossilList.length;
    }

    function getAgentsPaginated(uint256 offset, uint256 limit)
        external
        view
        returns (address[] memory)
    {
        uint256 end = offset + limit > agentList.length ? agentList.length : offset + limit;
        address[] memory result = new address[](end - offset);
        for (uint256 i = offset; i < end; i++) {
            result[i - offset] = agentList[i];
        }
        return result;
    }

    function getFossilsPaginated(uint256 offset, uint256 limit)
        external
        view
        returns (address[] memory)
    {
        uint256 end = offset + limit > fossilList.length ? fossilList.length : offset + limit;
        address[] memory result = new address[](end - offset);
        for (uint256 i = offset; i < end; i++) {
            result[i - offset] = fossilList[i];
        }
        return result;
    }

    function isAlive(address agent) external view returns (bool) {
        return registered[agent] && genomes[agent].alive && !extinct[agent];
    }
}

contracts/PhotonicVerifier.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/// @title PhotonicVerifier — BPD staking and peer verification
/// @notice Verifiers stake ETH to participate in BPD verification and earn/lose based on accuracy.
contract PhotonicVerifier is Ownable, ReentrancyGuard {

    // ─────────────────────────────────────────────────────────────────────
    //  Types
    // ─────────────────────────────────────────────────────────────────────

    enum VerificationStatus { Pending, Consensus, Disputed, Slashed }

    struct BPDRecord {
        bytes32 bpdHash;             // Hash(intent || output || trace || timestamp || nonce)
        address provider;
        uint256 deliveryFee;
        uint256 stakedTotal;
        uint256 verifierCount;
        uint256 consensusCount;      // verifiers who matched
        VerificationStatus status;
        uint64  createdAt;
        uint64  resolvedAt;
        bool    settled;
    }

    struct VerifierStake {
        uint256 amount;
        bytes32 submittedHash;       // The hash the verifier claims matches
        bool    matched;             // Set after resolution
        bool    claimed;
    }

    // ─────────────────────────────────────────────────────────────────────
    //  Storage
    // ─────────────────────────────────────────────────────────────────────

    mapping(bytes32 => BPDRecord) public bpdRecords;             // bpdId => record
    mapping(bytes32 => mapping(address => VerifierStake)) public stakes; // bpdId => verifier => stake
    mapping(bytes32 => address[]) public verifierList;           // bpdId => verifier addresses
    mapping(address => uint256) public verifierReputation;       // lifetime correct verifications
    mapping(address => uint256) public totalSlashed;

    uint256 public minStake = 0.001 ether;
    uint256 public verificationWindow = 30 minutes;
    uint256 public consensusThreshold = 67;    // 67% agreement = consensus
    uint256 public verifierRewardBps = 500;    // 5% of delivery fee split among verifiers

    bytes32[] public allBpdIds;

    // ─────────────────────────────────────────────────────────────────────
    //  Events
    // ─────────────────────────────────────────────────────────────────────

    event BPDSubmitted(bytes32 indexed bpdId, address indexed provider, bytes32 bpdHash, uint256 deliveryFee);
    event VerifierStaked(bytes32 indexed bpdId, address indexed verifier, uint256 amount, bytes32 submittedHash);
    event BPDResolved(bytes32 indexed bpdId, VerificationStatus status, uint256 consensusCount, uint256 totalVerifiers);
    event RewardClaimed(bytes32 indexed bpdId, address indexed verifier, uint256 reward);
    event SlashExecuted(bytes32 indexed bpdId, address indexed verifier, uint256 slashed);

    // ─────────────────────────────────────────────────────────────────────
    //  Constructor
    // ─────────────────────────────────────────────────────────────────────

    constructor() Ownable(msg.sender) {}

    // ─────────────────────────────────────────────────────────────────────
    //  BPD Lifecycle
    // ─────────────────────────────────────────────────────────────────────

    /// @notice Provider submits a BPD after delivering a task
    function submitBPD(
        bytes32 bpdId,
        bytes32 bpdHash,
        address provider
    ) external payable nonReentrant {
        require(bpdRecords[bpdId].createdAt == 0, "PhotonicVerifier: BPD already exists");
        require(msg.value > 0, "PhotonicVerifier: delivery fee required");

        bpdRecords[bpdId] = BPDRecord({
            bpdHash: bpdHash,
            provider: provider,
            deliveryFee: msg.value,
            stakedTotal: 0,
            verifierCount: 0,
            consensusCount: 0,
            status: VerificationStatus.Pending,
            createdAt: uint64(block.timestamp),
            resolvedAt: 0,
            settled: false
        });

        allBpdIds.push(bpdId);
        emit BPDSubmitted(bpdId, provider, bpdHash, msg.value);
    }

    /// @notice Verifier stakes and submits their re-execution result
    function stakeAndVerify(
        bytes32 bpdId,
        bytes32 submittedHash
    ) external payable nonReentrant {
        BPDRecord storage record = bpdRecords[bpdId];
        require(record.createdAt > 0, "PhotonicVerifier: BPD not found");
        require(record.status == VerificationStatus.Pending, "PhotonicVerifier: already resolved");
        require(block.timestamp < record.createdAt + verificationWindow, "PhotonicVerifier: window closed");
        require(msg.value >= minStake, "PhotonicVerifier: below min stake");
        require(stakes[bpdId][msg.sender].amount == 0, "PhotonicVerifier: already staked");
        require(msg.sender != record.provider, "PhotonicVerifier: provider cannot self-verify");

        stakes[bpdId][msg.sender] = VerifierStake({
            amount: msg.value,
            submittedHash: submittedHash,
            matched: false,
            claimed: false
        });

        verifierList[bpdId].push(msg.sender);
        record.stakedTotal += msg.value;
        record.verifierCount++;

        emit VerifierStaked(bpdId, msg.sender, msg.value, submittedHash);
    }

    /// @notice Resolve a BPD after the verification window closes
    function resolveBPD(bytes32 bpdId) external nonReentrant {
        BPDRecord storage record = bpdRecords[bpdId];
        require(record.createdAt > 0, "PhotonicVerifier: BPD not found");
        require(record.status == VerificationStatus.Pending, "PhotonicVerifier: already resolved");
        require(block.timestamp >= record.createdAt + verificationWindow, "PhotonicVerifier: window still open");

        if (record.verifierCount == 0) {
            record.status = VerificationStatus.Consensus;
            record.resolvedAt = uint64(block.timestamp);
            emit BPDResolved(bpdId, record.status, 0, 0);
            return;
        }

        // Count verifiers that match the provider's BPD hash
        uint256 matchCount = 0;
        address[] storage verifiers = verifierList[bpdId];
        for (uint256 i = 0; i < verifiers.length; i++) {
            VerifierStake storage s = stakes[bpdId][verifiers[i]];
            if (s.submittedHash == record.bpdHash) {
                s.matched = true;
                matchCount++;
            }
        }

        record.consensusCount = matchCount;
        uint256 matchPct = (matchCount * 100) / record.verifierCount;

        record.status = matchPct >= consensusThreshold
            ? VerificationStatus.Consensus
            : VerificationStatus.Disputed;
        record.resolvedAt = uint64(block.timestamp);

        emit BPDResolved(bpdId, record.status, matchCount, record.verifierCount);
    }

    /// @notice Claim rewards (matching verifiers) or settle slashes (mismatching verifiers)
    function claimReward(bytes32 bpdId) external nonReentrant {
        BPDRecord storage record = bpdRecords[bpdId];
        require(record.status != VerificationStatus.Pending, "PhotonicVerifier: not resolved");

        VerifierStake storage stake = stakes[bpdId][msg.sender];
        require(stake.amount > 0, "PhotonicVerifier: no stake");
        require(!stake.claimed, "PhotonicVerifier: already claimed");

        stake.claimed = true;

        if (record.status == VerificationStatus.Consensus && stake.matched) {
            // Matching verifiers get stake back + share of verifier reward pool
            uint256 rewardPool = (record.deliveryFee * verifierRewardBps) / 10000;
            uint256 share = rewardPool / record.consensusCount;
            uint256 payout = stake.amount + share;
            (bool ok,) = msg.sender.call{value: payout}("");
            require(ok, "PhotonicVerifier: transfer failed");
            verifierReputation[msg.sender]++;
            emit RewardClaimed(bpdId, msg.sender, payout);
        } else {
            // Non-matching verifiers are slashed — stake goes to provider
            totalSlashed[msg.sender] += stake.amount;
            (bool ok,) = record.provider.call{value: stake.amount}("");
            require(ok, "PhotonicVerifier: slash transfer failed");
            emit SlashExecuted(bpdId, msg.sender, stake.amount);
        }
    }

    // ─────────────────────────────────────────────────────────────────────
    //  Admin
    // ─────────────────────────────────────────────────────────────────────

    function setMinStake(uint256 _min) external onlyOwner { minStake = _min; }
    function setVerificationWindow(uint256 _window) external onlyOwner { verificationWindow = _window; }
    function setConsensusThreshold(uint256 _pct) external onlyOwner {
        require(_pct <= 100, "invalid");
        consensusThreshold = _pct;
    }

    // ─────────────────────────────────────────────────────────────────────
    //  Views
    // ─────────────────────────────────────────────────────────────────────

    function getBPDRecord(bytes32 bpdId) external view returns (BPDRecord memory) {
        return bpdRecords[bpdId];
    }

    function getVerifiers(bytes32 bpdId) external view returns (address[] memory) {
        return verifierList[bpdId];
    }

    function getStake(bytes32 bpdId, address verifier) external view returns (VerifierStake memory) {
        return stakes[bpdId][verifier];
    }

    function totalBPDs() external view returns (uint256) {
        return allBpdIds.length;
    }
}

